import 'dart:io';import 'package:flutter/services.dart';class AssetExtractor {  static const _channel = MethodChannel('com.besmartai.app/asset_extractor');  static Future<bool> extractTo({    required String assetPath,    required String outputPath,  }) async {    final outputFile = File(outputPath);    if (await outputFile.exists()) return true;    try {      final result = await _channel.invokeMethod<String>('extractModel', {        'assetPath': assetPath,        'outputPath': outputPath,      });      if (result == null || result.isEmpty) return false;      return await outputFile.exists();    } catch (e) {      try {        final bundleData = await rootBundle.load(assetPath);        final bytes = bundleData.buffer.asUint8List();        await outputFile.parent.create(recursive: true);        await outputFile.writeAsBytes(bytes);        return await outputFile.exists();      } catch (e2) {        return false;      }    }  }}